  /** Consume a token of an expected given kind, throwing an exception if different. */
  private Token jj_consume_token(final int kind, final String loc) throws ParseException {
    final Token oldToken = token;
    if (token.next != null) {
      token = token.next;
    } else {
      token = token.next = token_source.getNextToken();
    }
    jj_ntk = -1;
    if (token.kind == kind) {
      jj_gen++;
      if (++jj_gc > MAX_NB_POS) {
        jj_gc = 0;
        for (int i = 0; i < jj_2_rtns.length; i++) {
          JJCalls c = jj_2_rtns[i];
          while (c != null) {
            if (c.gen < jj_gen) {
              c.first = null;
            }
            c = c.next;
          }
        }
      }
      return token;
    }
    token = oldToken;
    jj_kind = kind;
    throw generateParseException(loc);
  }


  /** An (empty) error class to pass level 3 layers when the last level lookahead succeeds. */
  @SuppressWarnings("serial")
  private static final class LookaheadSuccess extends java.lang.RuntimeException {
    @Override
    public Throwable fillInStackTrace() {
      return this;
    }
  }

  /** A singleton error object to pass level 3 layers when the last scan matches,
   * thus making the lookahead succeeds. */
  private static final LookaheadSuccess jj_ls = new LookaheadSuccess();

  /** Scan for a token of a given expected kind, returning success or failure. */
  private boolean jj_scan_token(int kind, final String loc) {
    if (jj_scanpos == jj_lastpos) {
      jj_la--;
      if (jj_scanpos.next == null) {
        jj_lastpos = jj_scanpos = jj_scanpos.next = token_source.getNextToken();
      } else {
        jj_lastpos = jj_scanpos = jj_scanpos.next;
      }
    } else {
      jj_scanpos = jj_scanpos.next;
    }
    if (jj_rescan) {
      int i = 0;
      Token tok = token;
      while (tok != null && tok != jj_scanpos) {
        i++;
        tok = tok.next;
      }
      if (tok != null) {
        jj_add_error_token(kind, i, loc);
      }
    }
    if (jj_scanpos.kind != kind) {
      return LA_Scan_Token_Failure;
    }
    if (jj_la == 0 && jj_scanpos == jj_lastpos) {
      throw jj_ls;
    }
    return LA_Scan_Token_Success;
  }

  /**
   * Get the next token.
   *
   * @return the next token
   */
  public final Token getNextToken() {
    if (token.next != null) {
      token = token.next;
    } else {
      token = token.next = token_source.getNextToken();
    }
    jj_ntk = -1;
    jj_gen++;
    return token;
  }

  /**
   * Get a specific token.
   *
   * @param index token index
   * @return token at given position
   */
  public final Token getToken(int index) {
    Token t = jj_lookingAhead ? jj_scanpos : token;
    for (int i = 0; i < index; i++) {
      if (t.next != null) {
        t = t.next;
      } else {
        t = t.next = token_source.getNextToken();
      }
    }
    return t;
  }

  /** Get and chain the next token, and return its kind. */
